import React, { useState, useEffect } from 'react';
import API from '../api/axios';
import Navigation from '../components/Navigation';

const RoleMaster = () => {
    const [roles, setRoles] = useState([]);
    const [formData, setFormData] = useState({ roleName: '', description: '' });
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');
    const [isEditing, setIsEditing] = useState(false);
    const [editId, setEditId] = useState(null);

    const roleOptions = ['SuperAdmin', 'User', 'Networking Staff', 'Plumber', 'Electrician', 'Software Developer', 'Cleaner', 'Carpenter'];

    useEffect(() => { fetchRoles(); }, []);

    const fetchRoles = async () => {
        try {
            const { data } = await API.get('/master/role');
            setRoles(data);
        } catch (err) { console.error('Error fetching roles', err); }
    };

    const handleEdit = (role) => {
        setIsEditing(true);
        setEditId(role._id);
        setFormData({ roleName: role.roleName, description: role.description || '' });
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    const handleDelete = async (id) => {
        if (!window.confirm('Are you sure you want to delete this role?')) return;
        try {
            await API.delete(`/master/role/${id}`);
            fetchRoles();
            setMessage({ type: 'success', text: '✓ Role deleted successfully!' });
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error deleting role' });
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            if (isEditing) {
                await API.put(`/master/role/${editId}`, formData);
                setMessage({ type: 'success', text: '✓ Role updated successfully!' });
            } else {
                await API.post('/master/role', formData);
                setMessage({ type: 'success', text: '✓ Role added successfully!' });
            }
            setFormData({ roleName: '', description: '' });
            setIsEditing(false);
            setEditId(null);
            fetchRoles();
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: isEditing ? 'Error updating role' : 'Error adding role' });
        } finally {
            setLoading(false);
        }
    };

    const resetForm = () => {
        setFormData({ roleName: '', description: '' });
        setIsEditing(false);
        setEditId(null);
    };

    return (
        <div className="page-wrapper">
            <Navigation />
            <div className="content-area">
                <div className="header-section">
                    <h1 className="main-title">👥 Role Master</h1>
                    <p className="subtitle">Manage user roles and permissions</p>
                </div>

                {message && (
                    <div className={`alert ${message.type === 'success' ? 'alert-success' : 'alert-error'}`}>
                        {message.text}
                    </div>
                )}

                <div className="master-grid">
                    <div className="glass-card">
                        <form onSubmit={handleSubmit} className="form-body">
                            <h3 className="form-title">{isEditing ? '✏️ Edit Role' : '➕ Add New Role'}</h3>
                            <div className="form-group">
                                <label className="form-label">Role Name</label>
                                <select required value={formData.roleName}
                                    onChange={e => setFormData({ ...formData, roleName: e.target.value })}
                                    className="form-select">
                                    <option value="">Select Role</option>
                                    {roleOptions.map(role => <option key={role} value={role}>{role}</option>)}
                                </select>
                            </div>
                            <div className="form-group">
                                <label className="form-label">Description</label>
                                <textarea placeholder="Enter role description..."
                                    value={formData.description}
                                    onChange={e => setFormData({ ...formData, description: e.target.value })}
                                    className="form-textarea" />
                            </div>
                            <div className="form-actions">
                                <button type="submit" disabled={loading} className="btn btn-primary" style={{ flex: 1 }}>
                                    {loading ? 'Processing...' : (isEditing ? 'Update Role' : '+ Add Role')}
                                </button>
                                {isEditing && (
                                    <button type="button" onClick={resetForm} className="btn btn-secondary">
                                        Cancel
                                    </button>
                                )}
                            </div>
                        </form>
                    </div>

                    <div className="table-card">
                        <h3 className="table-title">📋 Roles List</h3>
                        <div className="table-scroll">
                            <table className="data-table">
                                <thead>
                                    <tr>
                                        <th>Role Name</th>
                                        <th>Description</th>
                                        <th style={{ textAlign: 'center' }}>Actions</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {roles.length > 0 ? (
                                        roles.map(role => (
                                            <tr key={role._id}>
                                                <td><span className="badge badge-accent">{role.roleName}</span></td>
                                                <td>{role.description || '-'}</td>
                                                <td className="table-actions">
                                                    <button onClick={() => handleEdit(role)} className="btn-icon-only" title="Edit">✏️</button>
                                                    <button onClick={() => handleDelete(role._id)} className="btn-icon-only text-error" title="Delete">🗑️</button>
                                                </td>
                                            </tr>
                                        ))
                                    ) : (
                                        <tr><td colSpan="3" className="table-empty">No roles found</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default RoleMaster;
